import AsyncStorage from '@react-native-async-storage/async-storage';
import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useRef,
  useState,
  type ReactNode,
} from 'react';

// Campaign-creation wizard state (US-049 through US-053). React-context + AsyncStorage
// persistence — not MMKV, because `react-native-mmkv` v4 is a Nitro module that
// cannot load in Expo Go (see Codebase Pattern #105, progress.txt). AsyncStorage
// satisfies the AC's "wizard store + MMKV" intent with a transport that actually
// boots in Expo Go. The wizard draft is not secret material, so AsyncStorage (vs
// expo-secure-store) is the correct fit.
//
// Shape covers all five steps up front so later stories (US-050 pre-conditions,
// US-051 post-conditions, US-052 samples + max, US-053 publish) can read and
// write their slices without a store rewrite. Step 1 (this story) only wires the
// first four fields; the rest are kept with empty-array / null defaults.

export type WizardCurrency = 'USD' | 'EUR' | 'GBP';

export type WizardPreConditionPlatform = 'tiktok' | 'instagram';
export type WizardPreConditionMetric = 'followers' | 'avg_views';

export type WizardPreCondition = {
  id: string;
  platform: WizardPreConditionPlatform;
  metric: WizardPreConditionMetric;
  threshold: number;
};

export type WizardPostCondition = {
  id: string;
  text: string;
};

export type WizardDraft = {
  title: string;
  description: string;
  priceCents: number | null;
  currency: WizardCurrency;
  preConditions: WizardPreCondition[];
  postConditions: WizardPostCondition[];
  sampleUrls: string[];
  maxSubmissions: number | null;
};

const EMPTY_DRAFT: WizardDraft = {
  title: '',
  description: '',
  priceCents: null,
  currency: 'USD',
  preConditions: [],
  postConditions: [],
  sampleUrls: [],
  maxSubmissions: null,
};

const STORAGE_KEY = '@marketify/campaign-wizard-draft/v1';
const PERSIST_DEBOUNCE_MS = 250;

type WizardContextValue = {
  draft: WizardDraft;
  hydrated: boolean;
  setField: <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => void;
  setPartial: (patch: Partial<WizardDraft>) => void;
  resetDraft: () => Promise<void>;
};

const WizardContext = createContext<WizardContextValue | null>(null);

function isWizardDraftShape(value: unknown): value is WizardDraft {
  if (!value || typeof value !== 'object') return false;
  const v = value as Record<string, unknown>;
  return (
    typeof v.title === 'string' &&
    typeof v.description === 'string' &&
    (v.priceCents === null || typeof v.priceCents === 'number') &&
    (v.currency === 'USD' || v.currency === 'EUR' || v.currency === 'GBP') &&
    Array.isArray(v.preConditions) &&
    Array.isArray(v.postConditions) &&
    Array.isArray(v.sampleUrls) &&
    (v.maxSubmissions === null || typeof v.maxSubmissions === 'number')
  );
}

export function WizardProvider({ children }: { children: ReactNode }) {
  const [draft, setDraft] = useState<WizardDraft>(EMPTY_DRAFT);
  const [hydrated, setHydrated] = useState(false);
  const persistTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    let cancelled = false;
    void (async () => {
      try {
        const raw = await AsyncStorage.getItem(STORAGE_KEY);
        if (cancelled) return;
        if (raw) {
          const parsed: unknown = JSON.parse(raw);
          if (isWizardDraftShape(parsed)) {
            setDraft(parsed);
          }
        }
      } catch {
        // Corrupted / missing draft — start clean. No user-visible error:
        // the wizard is a local-first flow and an empty draft is the right
        // fallback.
      } finally {
        if (!cancelled) setHydrated(true);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const schedulePersist = useCallback((next: WizardDraft) => {
    if (persistTimer.current) clearTimeout(persistTimer.current);
    persistTimer.current = setTimeout(() => {
      void AsyncStorage.setItem(STORAGE_KEY, JSON.stringify(next));
    }, PERSIST_DEBOUNCE_MS);
  }, []);

  useEffect(() => {
    return () => {
      if (persistTimer.current) clearTimeout(persistTimer.current);
    };
  }, []);

  const setField = useCallback(
    <K extends keyof WizardDraft>(key: K, value: WizardDraft[K]) => {
      setDraft((prev) => {
        const next = { ...prev, [key]: value };
        schedulePersist(next);
        return next;
      });
    },
    [schedulePersist],
  );

  const setPartial = useCallback(
    (patch: Partial<WizardDraft>) => {
      setDraft((prev) => {
        const next = { ...prev, ...patch };
        schedulePersist(next);
        return next;
      });
    },
    [schedulePersist],
  );

  const resetDraft = useCallback(async () => {
    if (persistTimer.current) {
      clearTimeout(persistTimer.current);
      persistTimer.current = null;
    }
    setDraft(EMPTY_DRAFT);
    await AsyncStorage.removeItem(STORAGE_KEY);
  }, []);

  const value = useMemo<WizardContextValue>(
    () => ({ draft, hydrated, setField, setPartial, resetDraft }),
    [draft, hydrated, setField, setPartial, resetDraft],
  );

  return <WizardContext.Provider value={value}>{children}</WizardContext.Provider>;
}

export function useWizard(): WizardContextValue {
  const ctx = useContext(WizardContext);
  if (!ctx) {
    throw new Error('useWizard must be used inside <WizardProvider>');
  }
  return ctx;
}

import { useCallback, useMemo, useState } from 'react';
import {
  KeyboardAvoidingView,
  Platform,
  Pressable,
  SafeAreaView,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  type TextInputProps,
  View,
} from 'react-native';
import { router } from 'expo-router';
import { ChevronLeft } from 'lucide-react-native';
import { ButtonPrimary } from '@/components/primitives/Button';
import { Chip } from '@/components/primitives/Chip';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { textStyles } from '@/design/typography';
import {
  useWizard,
  type WizardCurrency,
} from '@/screens/campaign-wizard/WizardStore';

// US-049 — Create-campaign wizard step 1 (basics: title, description, price,
// currency). Draft persisted via `WizardProvider` (Context + AsyncStorage).
// "Next" is gated on non-empty trimmed title + description per AC; price is
// optional and stored as cents to match `listings.price_cents`.
//
// Price is display-only in v1 per docs/product-plan.md §3.1 (no payments).
// The user enters major units (e.g. "49.50") — we parse to cents on change
// so the draft stays aligned with the DB column shape for step-5 publish.

const CURRENCIES: readonly WizardCurrency[] = ['USD', 'EUR', 'GBP'];
const CURRENCY_SYMBOL: Record<WizardCurrency, string> = {
  USD: '$',
  EUR: '€',
  GBP: '£',
};

// Accept up to two decimal places, e.g. "12", "12.50", ".5"; reject letters,
// multiple dots, etc. The dollars → cents conversion is Math.round on *100.
const PRICE_INPUT_RE = /^(\d+)?(\.\d{0,2})?$/;

function centsToDisplay(cents: number | null): string {
  if (cents === null) return '';
  // Render integer values without a trailing `.00` so round-trip is clean.
  if (cents % 100 === 0) return String(cents / 100);
  return (cents / 100).toFixed(2);
}

function displayToCents(display: string): number | null {
  const trimmed = display.trim();
  if (!trimmed) return null;
  const n = Number.parseFloat(trimmed);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.round(n * 100);
}

export default function CampaignWizardStep1() {
  const { draft, hydrated, setField, setPartial } = useWizard();

  // Local mirror of the price TextInput so we can keep partial input like "12."
  // without mangling it through cents round-trips. Initialized from the draft
  // once hydration finishes.
  const [priceDisplay, setPriceDisplay] = useState<string | null>(null);
  const effectivePriceDisplay =
    priceDisplay ?? (hydrated ? centsToDisplay(draft.priceCents) : '');

  const canProceed = useMemo(
    () => draft.title.trim().length > 0 && draft.description.trim().length > 0,
    [draft.title, draft.description],
  );

  const onTitleChange = useCallback(
    (next: string) => setField('title', next),
    [setField],
  );
  const onDescriptionChange = useCallback(
    (next: string) => setField('description', next),
    [setField],
  );

  const onPriceChange = useCallback(
    (next: string) => {
      if (next !== '' && !PRICE_INPUT_RE.test(next)) return;
      setPriceDisplay(next);
      setField('priceCents', displayToCents(next));
    },
    [setField],
  );

  const onCurrencyPick = useCallback(
    (currency: WizardCurrency) => {
      setPartial({ currency });
    },
    [setPartial],
  );

  const onNext = useCallback(() => {
    if (!canProceed) return;
    router.push('/(lister)/campaigns/new/step-2');
  }, [canProceed]);

  const onBack = useCallback(() => {
    if (router.canGoBack()) router.back();
    else router.replace('/(lister)/dashboard');
  }, []);

  return (
    <SafeAreaView style={styles.root}>
      <KeyboardAvoidingView
        style={styles.flex}
        behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      >
        <ScrollView
          contentContainerStyle={styles.scroll}
          keyboardShouldPersistTaps="handled"
        >
          <View style={styles.header}>
            <Pressable
              onPress={onBack}
              hitSlop={12}
              accessibilityRole="button"
              accessibilityLabel="Back"
              testID="wizard-step1-back"
              style={styles.backBtn}
            >
              <ChevronLeft size={24} color={colors.ink} />
            </Pressable>
            <Text style={[textStyles.micro, styles.stepLabel]} allowFontScaling={false}>
              Step 1 of 5
            </Text>
            <Text style={[textStyles.display, styles.title]}>New campaign</Text>
            <Text style={[textStyles.body, styles.subtitle]}>
              The basics creators see first.
            </Text>
          </View>

          <View style={styles.fields}>
            <Field
              label="Title"
              value={draft.title}
              onChange={onTitleChange}
              placeholder="e.g. Launch of LuxeDrop summer line"
              autoCapitalize="sentences"
              testID="wizard-step1-title"
            />
            <Field
              label="Description"
              value={draft.description}
              onChange={onDescriptionChange}
              placeholder="What creators need to know before applying."
              autoCapitalize="sentences"
              multiline
              testID="wizard-step1-description"
            />
            <Field
              label="Price (optional)"
              value={effectivePriceDisplay}
              onChange={onPriceChange}
              placeholder="0.00"
              keyboardType="decimal-pad"
              prefix={CURRENCY_SYMBOL[draft.currency]}
              testID="wizard-step1-price"
            />

            <View style={styles.currencyGroup}>
              <Text style={[textStyles.caption, styles.label]}>Currency</Text>
              <View style={styles.chipRow}>
                {CURRENCIES.map((c) => (
                  <Chip
                    key={c}
                    label={c}
                    active={draft.currency === c}
                    onPress={() => onCurrencyPick(c)}
                    accessibilityLabel={`Currency ${c}`}
                    testID={`wizard-step1-currency-${c}`}
                  />
                ))}
              </View>
            </View>
          </View>

          <ButtonPrimary
            label="Next"
            onPress={onNext}
            disabled={!canProceed}
            accessibilityLabel="Go to wizard step 2"
            testID="wizard-step1-next"
          />
        </ScrollView>
      </KeyboardAvoidingView>
    </SafeAreaView>
  );
}

type FieldProps = {
  label: string;
  value: string;
  onChange: (next: string) => void;
  placeholder?: string;
  autoCapitalize?: TextInputProps['autoCapitalize'];
  keyboardType?: TextInputProps['keyboardType'];
  multiline?: boolean;
  prefix?: string;
  testID?: string;
};

function Field({
  label,
  value,
  onChange,
  placeholder,
  autoCapitalize,
  keyboardType,
  multiline,
  prefix,
  testID,
}: FieldProps) {
  return (
    <View style={styles.field}>
      <Text style={[textStyles.caption, styles.label]}>{label}</Text>
      <View style={[styles.inputWrap, shadows.hard, multiline && styles.inputWrapMultiline]}>
        {prefix ? <Text style={[textStyles.body, styles.prefix]}>{prefix}</Text> : null}
        <TextInput
          value={value}
          onChangeText={onChange}
          placeholder={placeholder}
          placeholderTextColor={colors.ink40}
          autoCapitalize={autoCapitalize}
          keyboardType={keyboardType}
          multiline={multiline}
          style={[textStyles.body, styles.input, multiline && styles.inputMultiline]}
          accessibilityLabel={label}
          testID={testID}
        />
      </View>
    </View>
  );
}

